<?php
namespace WCSA\Support; defined('ABSPATH') || exit;
final class Helpers{ public static function faToEn(string $v):string{return strtr($v,['۰'=>'0','۱'=>'1','۲'=>'2','۳'=>'3','۴'=>'4','۵'=>'5','۶'=>'6','۷'=>'7','۸'=>'8','۹'=>'9','٠'=>'0','١'=>'1','٢'=>'2','٣'=>'3','٤'=>'4','٥'=>'5','٦'=>'6','٧'=>'7','٨'=>'8','٩'=>'9']);} public static function normalizeMobile(string $m):string{$m=self::faToEn(trim($m));$m=preg_replace('/[\s\-\(\)]/','',$m);$m=preg_replace('/[^0-9\+]/','',$m); if(preg_match('/^09\d{9}$/',$m))return '+98'.substr($m,1); if(preg_match('/^9\d{9}$/',$m))return '+98'.$m; if(preg_match('/^98\d{10}$/',$m))return '+'.$m; return $m;} public static function isValidMobile(string $m):bool{return (bool)preg_match('/^\+989\d{9}$/',$m);} public static function mobileNational(string $m):string{return preg_match('/^\+98(\d{10})$/',$m,$x)?'0'.$x[1]:$m;} public static function national(string $c):string{return preg_replace('/\D/','',self::faToEn($c));} public static function isValidNationalCode(string $c):bool{$c=self::national($c); if(!preg_match('/^\d{10}$/',$c)||preg_match('/^(\d)\1{9}$/',$c))return false; $s=0; for($i=0;$i<9;$i++)$s+=intval($c[$i])*(10-$i); $r=$s%11;$chk=intval($c[9]); return ($r<2&&$chk===$r)||($r>=2&&$chk===11-$r);} public static function otpHash(string $o,string $m):string{return hash_hmac('sha256',$o.'|'.$m,wp_salt('auth'));} public static function randomDigits(int $l):string{$l=max(4,min(8,$l));$o='';for($i=0;$i<$l;$i++)$o.=(string)random_int(0,9);return $o;} public static function safeRedirect(string $u,string $f=''):string{$f=$f?:home_url('/');return wp_validate_redirect($u,$f)?:$f;}}
